1182	// TestBindModeRejectsUnknownValue: an unrecognized per-path `bind` value fails
1183	// fast at load with a message naming the offending path.
1184	func TestBindModeRejectsUnknownValue(t *testing.T) {
1185		body := fill(edgeConfig)
1186		body = strings.Replace(body,
1187			"name = \"cellular\"\nsource_addr = \"192.0.2.20\"",
1188			"name = \"cellular\"\nsource_addr = \"192.0.2.20\"\nbind = \"bogus\"", 1)
1189		path := writeConfig(t, 0o600, body)
1190		_, err := Load(path)
1191		if err == nil {
1192			t.Fatal("expected unknown bind value to be rejected at load, got nil")
1193		}
1194		if !strings.Contains(err.Error(), `path "cellular"`) || !strings.Contains(err.Error(), "bind must be") {
1195			t.Fatalf("error = %q, want it to name path \"cellular\" and say \"bind must be\"", err.Error())
1196		}
1197	}
