1213	// readExampleFile returns the verbatim content of the repo's wanbond.example.toml,
1214	// so the tests below exercise the ACTUAL documented file rather than a hand-copied
1215	// literal that could silently drift from it.
1216	func readExampleFile(t *testing.T) string {
1217		t.Helper()
1218		raw, err := os.ReadFile(filepath.Join("..", "..", "wanbond.example.toml"))
1219		if err != nil {
1220			t.Fatalf("read wanbond.example.toml: %v", err)
1221		}
1222		return string(raw)
1223	}
