1225	// extractExampleSection returns the text strictly between startMarker (exclusive —
1226	// the marker's own line, typically prose like "# EXAMPLE 1 (...):" or a section
1227	// header, is dropped) and endMarker (exclusive), with exactly one level of leading
1228	// "#" TOML-comment marker stripped from every line that has one at column 0. A
1229	// continuation line that is itself an aligned comment (e.g. wrapped explanatory
1230	// text with no leading "#" at column 0) is left untouched, mirroring exactly what a
1231	// human uncommenting the block by hand would do. This is how every commented-out
1232	// example in wanbond.example.toml is meant to be activated, so it is also the
1233	// correct way to extract and load one for testing.
1234	func extractExampleSection(t *testing.T, content, startMarker, endMarker string) string {
1235		t.Helper()
1236		start := strings.Index(content, startMarker)
1237		if start < 0 {
1238			t.Fatalf("start marker %q not found in wanbond.example.toml", startMarker)
1239		}
1240		rest := content[start:]
1241		end := len(rest)
1242		if endMarker != "" {
1243			idx := strings.Index(rest, endMarker)
1244			if idx < 0 {
1245				t.Fatalf("end marker %q not found after %q in wanbond.example.toml", endMarker, startMarker)
1246			}
1247			end = idx
1248		}
1249		lines := strings.Split(rest[:end], "\n")
1250		lines = lines[1:] // drop the marker's own (prose/header) line
1251		for i, ln := range lines {
1252			if strings.HasPrefix(ln, "#") {
1253				ln = strings.TrimPrefix(ln, "#")
1254				ln = strings.TrimPrefix(ln, " ")
1255				lines[i] = ln
1256			}
1257		}
1258		return strings.Join(lines, "\n")
1259	}
