1261	// fillExamplePlaceholders substitutes wanbond.example.toml's literal <base64 ...>
1262	// placeholders with syntactically valid test key material, mirroring fill()'s
1263	// %PRIV%/%PUB%/%PSK% substitution for the hand-written fixtures above.
1264	func fillExamplePlaceholders(s string) string {
1265		r := strings.NewReplacer(
1266			"<base64 32-byte PSK>", testKey(3),
1267			"<base64 32-byte private key>", testKey(1),
1268			"<base64 peer public key>", testKey(2),
1269		)
1270		return r.Replace(s)
1271	}
