1273	// exampleTopSection returns wanbond.example.toml's content from the start up to
1274	// (excluding) the live "[[wireguard.peers]]" table header: role/psk/paths/
1275	// wireguard.private_key, with placeholders filled.
1276	func exampleTopSection(t *testing.T, content string) string {
1277		t.Helper()
1278		idx := strings.Index(content, "\n[[wireguard.peers]]\n")
1279		if idx < 0 {
1280			t.Fatal("live [[wireguard.peers]] header not found in wanbond.example.toml")
1281		}
1282		return fillExamplePlaceholders(content[:idx+1])
1283	}
