1285	// exampleLiteralPeer returns the live, IP-literal first peer block (public_key,
1286	// endpoint, allowed_ips, plus inert commented optional lines), with placeholders
1287	// filled.
1288	func exampleLiteralPeer(t *testing.T, content string) string {
1289		t.Helper()
1290		start := strings.Index(content, "\n[[wireguard.peers]]\n")
1291		if start < 0 {
1292			t.Fatal("live [[wireguard.peers]] header not found in wanbond.example.toml")
1293		}
1294		end := strings.Index(content, "\n# ── second peer example")
1295		if end < 0 {
1296			t.Fatal("second peer example marker not found in wanbond.example.toml")
1297		}
1298		return fillExamplePlaceholders(content[start+1 : end+1])
