// per-peer psk+name values must expose each peer's own psk and name.
func TestLoadPeerPSKName(t *testing.T) {
	r := strings.NewReplacer(
		"%PRIV%", testKey(1),
		"%PUB1%", testKey(2),
		"%PSK%", testKey(3),
		"%PUB2%", testKey(4),
